LocalizationManager:add_localized_strings({
--Перчатки(Описание/Названия)
    ["bm_gloves_beigedriver"] = "Норма для лунки",
	["bm_gloves_beigedriver_desc"] = "Вы попадаете в лунку с первого раза, всегда.",
	["bm_gloves_chromecross"] = "Хром и кости",
	["bm_gloves_chromecross_desc"] = "Хоть на просторах морей, хоть на открытой трассе - пиратская жизнь всегда по вам.",
	["bm_gloves_darkmat"] = "Темная материя",
	["bm_gloves_darkmat_desc"] = "Вы - космическая сила, невидимая, но неоспоримая. Никто никогда не видел вас, но все ежедневно наблюдают последствия вашей гравитации. Вы везде и нигде.",
	["bm_gloves_devilclaws"] = "Фаустовская сделка",
	["bm_gloves_devilclaws_desc"] = "Давай закрепим это рукопожатием.",
	["bm_gloves_dodskull"] = "Гробовщик",
	["bm_gloves_dodskull_desc"] = "Что ж, это твои похороны.",
	["bm_gloves_leatherspark"] = "Магическое касание",
	["bm_gloves_leatherspark_desc"] = "Вы когда-нибудь крали бриллиант в бриллиантовых перчатках? Вот ЭТО я понимаю - роскошь!",
	["bm_gloves_railwork"] = "Инженер",
	["bm_gloves_railwork_desc"] = "Благодаря вам денежный поезд всегда приходит по расписанию.",
	["bm_gloves_ranchdiesel"] = "Работник ранчо",
	["bm_gloves_ranchdiesel_desc"] = "Нужна твердая рука, чтобы справляться с тяготами и невзгодами жизни на ранчо. Особенно когда твое ранчо - это прикрытие для крупной операции по контрабанде оружия.",
	["bm_gloves_redhand"] = "Пойман с поличным",
	["bm_gloves_redhand_desc"] = "Они поймали вас, но вы заставите их пожалеть об этом.",
	["bm_gloves_roclogrip"] = "Наездник быка",
	["bm_gloves_roclogrip_desc"] = "Для всех остальных это самый опасный вид спорта в мире. Для вас - обычный вторник.",
	["bm_gloves_spikeknuckle_desc"] = "Взрывоопасный, дерзкий и острый под любым углом. О да, эта перчатка точно для вас.",
	["bm_gloves_tasslefringe"] = "Колонизатор",
	["bm_gloves_tasslefringe_desc"] = "Этот материал просто отлично отмывается от крови!",
	["bm_gloves_tiger_neon"] = "Мечта тигра",
	["bm_gloves_tiger_neon_desc"] = "Охотьтесь всю ночь напролет.",
	["bm_gloves_tiger_red"] = "Когти тигра",
	["bm_gloves_tiger_red_desc"] = "Вы заслужили свои полоски.",
	["bm_gloves_tornrags"] = "Прикосновение смерти",
	["bm_gloves_tornrags_desc"] = "Вот это боевой настрой!",
	["bm_gloves_txbull"] = "Погонщик",
	["bm_gloves_txbull_desc"] = "Крутые перчатки, но оставь корову в покое!",
	["bm_gloves_txrider"] = "Беспечный ездок",
	["bm_gloves_txrider_desc"] = "Вы делаете то, что хотите, и когда хотите.",
	["bm_gloves_txrivet"] = "Называй вещи своими именами",
	["bm_gloves_txrivet_desc"] = "Говори все как есть.",
	["bm_gloves_txsuede"] = "Игрок",
	["bm_gloves_txsuede_desc"] = "Всегда ставьте на себя.",

--Маски(Описание/Названия)
    ["bm_msk_bandcap_dark"] = "Государственное преступление",
	["bm_msk_bandcap_dark_desc"] = "Когда вы грабите заправку в Амарилло, эта кепка дает кассиру понять, что его деньги останутся в регионе.",
	["bm_msk_banshee"] = "Гейст",
	["bm_msk_banshee_desc"] = "Некоторые духи довольствуются тем, что влачат жалкое существование на грани бытия, двигая мебель и завывая по ночам. Другие жаждут более осязаемого влияния. Совсем недавно полиция округа Колумбия сообщила о резком скачке паранормальной активности в крупнейших банках, художественных музеях и ювелирных магазинах города. Очевидцы утверждали, что ценные предметы буквально сами выплывали за дверь. Должно быть, это призраки давно погибших грабителей вернулись за последним делом.",
	["bm_msk_biker_helmet_red_led_desc"] = "Этот потрясающий шлем придаст вам стильный аэродинамический вид; дизайнер явно слушал вейпорвейв на полную мощность, когда создавал его.",
	["bm_msk_biker_helmet_yellow_led_desc"] = "Этот неоновый красавец вдохновит вас ворваться, провести дело с хирургической точностью и убраться со всеми шмотками.",
	["bm_msk_bloodysnarl"] = "Вампир",
	["bm_msk_bloodysnarl_desc"] = "Мнения разделились насчет того, получились бы из вампиров хорошие грабители. Способности к гипнозу, превращение в летучую мышь - все это огромные плюсы. Но они не могут войти в здание без приглашения. Значит, взлом с проникновением отпадает. И раз у них нет отражения, будут ли они видны на камерах наблюдения? Надо будет спросить у наших друзей-вампиров.",
	["bm_msk_boss_gold_desc"] = "Как назвать маску из чистого золота? Смелое заявление, вот как.",
	["bm_msk_bossflagmask"] = "Мидлендский мемориал",
	["bm_msk_bossflagmask_desc"] = "Эстебан Сантьяго не был хорошим человеком. Он не был приятным человеком. Или хотя бы приличным. Но он обожал пушки. И он обожал Техас. И он обожал контрабанду армейского оружия в Техас. А еще он умел чертовски вкусно коптить грудинку.\nИ эй... По крайней мере, он не был таким отбитым наглухо, как его брат. Я ведь прав?",
	["bm_msk_bthekidmask"] = "Билли",
	["bm_msk_bthekidmask_desc"] = "В каждом ремесле есть свои вундеркинды. В музыке - Моцарт, в искусстве - Пикассо, а среди преступников - Билли Кид. К 21 году Билли убил более двадцати человек и бесчисленное количество раз уходил от закона. Он был самым быстрым стрелком на Диком Западе, свободно говорил по-испански и искренне нравился всем, кто его встречал. Прожил он недолго, но, черт возьми, ценил каждую секунду.",
	["bm_msk_cassidymask"] = "Бутч",
	["bm_msk_cassidymask_desc"] = "Как и большинство из нас, Роберт ЛеРой Паркер не выбирал имя при рождении. Но когда он решил покончить со старой жизнью и стать преступником, он сжег свою прежнюю личность. Вдохновившись временами, когда он был учеником мясника, и памятью о своем любимом наставнике Майке Кэссиди, он придумал себе совершенно новое имя. Никто не говорит о Роберте ЛеРое Паркере, но Бутч Кэссиди... Вот это имя легенды.",
	["bm_msk_chrodome"] = "Хромированный купол",
	["bm_msk_chrodome_desc"] = "Есть причина, по которой вы держите свой шлем таким блестящим и безупречно чистым. Так в нем гораздо красивее отражаются взрывы машин, которые вы подрываете.",
	["bm_msk_daredev"] = "Сорвиголова",
	["bm_msk_daredev_desc"] = "Идеальный момент. Зависнув в воздухе, оставив мотоциклетный трамплин позади, вы видите, как противоположный край Большого каньона приближается с каждой секундой. Приземлитесь ли вы удачно или рухнете насмерть? Этот вопрос даже не приходит вам в голову. Прямо сейчас, возможно, впервые в жизни... Вы по-настоящему живы.",
	["bm_msk_devilhorn"] = "Мефистофель",
	["bm_msk_devilhorn_desc"] = "У Обманщика было много имен и обличий. С самого начала времен он шептал нам из тени, развращая наши души и подталкивая к неописуемым поступкам. Он может сеять разрушение, даже не пошевелив пальцем... Но это как-то скучно, понимаете? Иногда старине Сатане просто хочется воплотиться на Земле в виде огромного демона, побегать и пограбить какое-нибудь дерьмо. Неужели это так много?",
	["bm_msk_dodhat"] = "Теларанья",
	["bm_msk_dodhat_desc"] = "Ваша жизнь - это запутанная череда историй и сюжетных нитей, тщательно вплетенных в гобелен под названием \"легенда\". Спустя долгое время после вашего ухода подражатели увязнут в вашем наследии, как мухи в паутине. Они будут тщетно пытаться вырваться из вашей тени, и ваша тень поглотит их всех.",
	["bm_msk_elfhat"] = "Зеленый эльф",
	["bm_msk_elfhat_desc"] = "Социопат с дипломом химика, Зеленый эльф - штатный эксперт Северного полюса по ядам и нейротоксинам.",
	["bm_msk_elfhat_red"] = "Красный эльф",
	["bm_msk_elfhat_red_desc"] = "Как солдат рождественского ополчения Санты, Красный эльф любит купаться в крови своих врагов. А вы бы не хотели?",
	["bm_msk_elfhat_violet"] = "Фиолетовый эльф",
	["bm_msk_elfhat_violet_desc"] = "Фиолетовый эльф на самом деле очень спокойный парень. Конечно, он некромант, который то ли приносит человеческие жертвы, то ли нет, но в остальном он супермилый.",
	["bm_msk_elfhat_yellow"] = "Желтый эльф",
	["bm_msk_elfhat_yellow_desc"] = "За его жизнерадостным характером скрывается яростный пироман, который не успокоится, пока не выжжет весь Скверный список из этого мира.",
	["bm_msk_flapcapban"] = "Плохой таксист",
	["bm_msk_flapcapban_desc"] = "Внезапно вы понимаете, что устали зарабатывать на жизнь развозом идиотов. Вы находитесь в глухом районе города, а на заднем сиденье сидит какой-то зажравшийся козел. Наверняка у него в кармане лежит косарь баксов наличными, не меньше. Вокруг никого, кто мог бы вас остановить, и вы вспоминаете, что в бардачке припрятан 9-миллиметровый. Сверните в переулок и заберите плату за проезд.",
	["bm_msk_funguy"] = "Весельчак",
	["bm_msk_funguy_desc"] = "Когда он рассказывает шутку - смейтесь. Смейтесь сильно, смейтесь долго, смейтесь, пока в легких не кончится воздух, а затем продолжайте смеяться. Потому что если вы остановитесь, он разозлится. Когда он злится, он хочет есть. А когда он хочет есть... Ну, вы, наверное, и сами догадываетесь, в чем соль шутки.",
	["bm_msk_gabhelm"] = "Реквием Габриэля",
	["bm_msk_gabhelm_desc"] = "В то время как его младший брат Эстебан любил продавать оружие, Габриэль Сантьяго предпочитал из него стрелять. Он служил в морской пехоте, затем годы работал на ЧВК Bellmead International, пока его безжалостная эффективность не привлекла внимание нефтяной баронессы Элис Рэйни. Желая использовать его боевое мастерство и криминальные связи, она предложила Габриэлю должность начальника службы безопасности SERA. В поисках богатства и статуса он согласился.\nКогда Рэйни выразила желание укрепить свои позиции в техасском преступном мире, Габриэль познакомил ее с Эстебаном, который к тому времени руководил операцией по контрабанде оружия с ранчо Мидленд. Их встреча вывела братьев Сантьяго на неожиданную траекторию столкновения с бандой Payday, и это стало гибелью для Габриэля. Жестокая жизнь ведет к жестокой смерти.",
	["bm_msk_gentgla_brown"] = "Агент Браун",
	["bm_msk_gentgla_brown_desc"] = "Когда Агентству нужен более мягкий подход, они посылают Агента Брауна. Он из тех парней, которые предлагают сигарету перед допросом. Настоящая душа компании, отличное чувство юмора. Он заставит вас смеяться так сильно, что вы даже не заметите его пистолет, пока он не упрется вам в живот.",
	["bm_msk_gentgla_dark"] = "Агент Блэк",
	["bm_msk_gentgla_dark_desc"] = "О отлично, а вот и Агент Блэк. Этот парень - настоящий псих. Пытки электротоком, удушение струной от пианино - это все по его части. Агентство выпускает его с поводка только тогда, когда количество трупов перестает кого-либо волновать. При всем при этом он невероятно мил со стариками. Люди - сложные существа, я полагаю.",
	["bm_msk_guldgris"] = "Копилкин",
	["bm_msk_guldgris_desc"] = "Золотая свинья - символ процветания и новых начинаний. Идеальная маска для такого случая. После стольких лет риска вы всегда пожинали плоды. Столько наград завоевано, но всегда есть за что побороться снова. За вашу дальнейшую удачу и за то, чтобы впереди было еще много ограблений!",
	["bm_msk_hatgla_dark"] = "Крутая черная шапка",
	["bm_msk_hatgla_dark_desc"] = "Это моя шапка. Таких шапок много, но эта - моя. Моя шапка - мой лучший друг. Это моя жизнь. Я должен овладеть своей шапкой так же, как должен овладеть своей жизнью.",
	["bm_msk_hatgla_green"] = "Крутая зеленая шапка",
	["bm_msk_hatgla_green_desc"] = "Вы когда-нибудь замечали, что люди, которые носят шапки-бини, вообще НИКОГДА их не снимают? Я знаю одного парня уже десять лет, он носит точно такую же шапку, и я ни разу не видел макушку его головы. Ни разу.",
	["bm_msk_homburg"] = "Семьянин (Темная)",
	["bm_msk_homburg_desc"] = "Никогда не вставай на сторону кого-либо против семьи.",
	["bm_msk_homburg_grey"] = "Семьянин (Серая)",
	["bm_msk_homburg_grey_desc"] = "Помни: всегда находи время для тех, кого любишь, но не позволяй им расспрашивать о твоих делах.",
	["bm_msk_jessjamesmask"] = "Джесси",
	["bm_msk_jessjamesmask_desc"] = "Когда вы оказываетесь на проигрывающей стороне в битве, у вас есть два варианта. Вы можете поднять руки и сдаться, либо продолжить стрелять. Джесси Джеймс выбрал второе. Вместо того чтобы вывесить белый флаг, он превратился из военного преступника в обычного бандита, и Дикий Запад стал его полем боя. Говорите что хотите об этом мародере и убийце, но он никогда не опускал руки. Никогда не сдавался.",
	["bm_msk_mega_richard_returns"] = "Мега-Ричард возвращается",
	["bm_msk_mega_richard_returns_desc"] = "В мире, где гангстеры все еще ходят с целыми черепами, один человек и одна бита - единственное решение.\nВ главных ролях: Нейтан Стил в роли Далласа, Николас в роли Чейнса, Хьюстон в роли Хокстона и *звуки аудиоленты* в роли Джекета в боевике \"Мега-Ричард возвращается в Вашингтон\".",
	["bm_msk_megaskulldia"] = "Девятьсот градусов",
	["bm_msk_megaskulldia_desc"] = "Блерри! Похоже, алмазы, которые я использовал для создания этой маски, были наделены какой-то мистической энергией! Вы замечаете пророческие видения? Может, новые божественные силы? Нет? Просто глаза жжет? Ну, в любом случае выглядит круто!",
	["bm_msk_mts_trol"] = "Тролль Ларс",
	["bm_msk_mts_trol_desc"] = "Некоторые уже боятся вас, как тролля или огра из древних сказок. Так почему бы не соответствовать образу, опустошая сундуки в их замке?",
	["bm_msk_oilbaron"] = "Техасский чай",
	["bm_msk_oilbaron_desc"] = "Оно ждало миллионы лет.\n\nКогда-то оно было многим - бесчисленными крошечными организмами, погибшими и погребенными. Сдавленные временем, выжженные теплом планеты, они превратились в единую черную массу. Бурлящая жидкость, не подозревающая о своей ценности. Безымянная вещь. Ожидающая вещь.\n\nТысячелетия пролетали как минуты, пока эпоха ожидания не подошла к концу. Оглушительный гул заставил безымянную вещь вырваться наружу из темного чрева Земли. Вверх из земли, вверх по металлической вышке, взрываясь навстречу техасскому солнцу, словно вулкан. Оно явилось под фанатичные аплодисменты, слезы радости и алчности, и когда оно пролилось дождем на своих почитателей, ухмыляющееся лицо дало ему имя:\n\n\"Ну что, парни, похоже, мы качнули нефть\".\n",
	["bm_msk_primtime"] = "Прайм-тайм",
	["bm_msk_primtime_desc"] = "СЕГОДНЯ В ЭФИРЕ! Наши финалисты надевают квантовые маски и отправляются в XXI век! Вооруженные лишь примитивным оружием той эпохи, они должны украсть как можно больше богатств, пока не истечет время!\n\nКто выживет? Кто вернется с самой большой добычей? Кто пожажимает руку легендарной банде Payday? Узнайте сегодня в шоу... \"ОГРАБЛЕНИЕ В БУДУЩЕЕ\"!",
	["bm_msk_railhat"] = "Зеленый свет",
	["bm_msk_railhat_desc"] = "Полный вперед, команда! Мы строили железные дороги не для того, чтобы прибыть на место завтра! Я хочу быть там ЕЩЕ ВЧЕРА! Погнали, сучки!",
	["bm_msk_roclown"] = "Последнее родео",
	["bm_msk_roclown_desc"] = "У каждого преступника в жизни есть свой бык. Возможно, это паршивый босс конкурирующей банды, пытающийся залезть на твою территорию. Или ростовщик, которому деньги нужны были еще вчера. Или инспектор по УДО, мечтающий упечь тебя обратно за решетку. Ты уже давно кружишь в танце с этим быком. Раз за разом ты готовишься к следующему выпаду, надеясь успеть увернуться. Молясь, чтобы тебя не растоптали в клочья.\nХватит. С танцами покончено. В следующий раз, когда вы сойдетесь лицом к лицу, ты возьмешь этого быка за рога, вырвешь их и засунешь ему в задницу. Это далеко не первое твое родео, но для него оно станет последним. И-ха, ублюдки.",
	["bm_msk_sambassmask"] = "Сэм",
	["bm_msk_sambassmask_desc"] = "Если вы думаете, что скрытное прохождение - это слишком сложно, вспомните вот что. Басс и его банда провернули одно из крупнейших ограблений поездов в американской истории, урвав целое состояние в золотых монетах, и сделали это, не убив ни единого человека. Ноль жертв, вся добыча вывезена. Если они смогли провернуть такое дерьмо без навыков вора, то вы уж точно сможете ответить на пару пейджеров, не поднимая тревоги.",
	["bm_msk_skulldia"] = "Девять жизней",
	["bm_msk_skulldia_desc"] = "Надо отдать вам должное, ребята. Вы добились немалого всего за девять коротких лет. Сколько мест вы обчистили? Сколько замков взломали? Скольких копов, дантистов и слизких, заносчивых, жаждущих власти уродов вы отправили на тот свет? И пусть наше знакомство началось не гладко, посмотрите на нас теперь! Вы приняли меня в свою банду. Это очень много значило для меня, друзья.\nЯ заказал эту маску в знак благодарности. Кстати, это настоящие южноафриканские алмазы!",
	["bm_msk_smilecigar"] = "Шишка",
	["bm_msk_smilecigar_desc"] = "С вашей стодолларовой сигарой и миллионной улыбкой никому и никогда не придется спрашивать, кто здесь главный.",
	["bm_msk_speedfreak"] = "Поехавший",
	["bm_msk_speedfreak_desc"] = "Если голоса в твоей голове хотят свести тебя с ума, им сначала придется тебя догнать.",
	["bm_msk_splitcrim"] = "Банда Кинцуги",
	["bm_msk_splitcrim_desc"] = "Оригиналы. Грабители-основатели, объединенные одной миссией: взять сумку. Кради сколько сможешь и пока можешь. Мир постоянно пытался расколоть их, но они всегда собирались вместе снова. Кинцуги - это японское искусство реставрации битой керамики с помощью золотого лака. Прославление истории, а не ее сокрытие. У этих клоунов общее золотое наследие, и оно навсегда свяжет их вместе. Самая. Сплоченная. Команда. В ИСТОРИИ!",
	["bm_msk_teddymoo"] = "Тедди Му",
	["bm_msk_teddymoo_desc"] = "Наконец-то маска, которая заявляет: \"Поберегись, мир! Я могу казаться милым, но у меня в заднице спрятана циркулярная пила!\" Обнимайте на свой страх и риск.",
	["bm_msk_threap"] = "Жнец",
	["bm_msk_threap_desc"] = "Вы видели его на фотографиях замесов из десяти машин, в новостных репортажах о столкновениях грузовиков - он всегда проносится мимо места жуткой аварии. Мотоциклист, укутанный с ног до головы в черное, чье бледное лицо смазывается от скорости. Вам говорят, что это просто какой-то байкер. Один на миллион. Но вы знаете, что уже видели его раньше. Вам кажется, что вы видите его прямо сейчас, едущего чуть впереди вас по этой ледяной, слепящей снегом автомагистрали...\nИ именно в этот момент вы понимаете, что у вас отказали тормоза.",
	["bm_msk_uno_01"] = "Глаза мертвеца",
	["bm_msk_uno_01_desc"] = "Вам велели сжечь труп вместе с одеждой. Не оставлять следов. И вот он отправляется в печь. Максимальный жар. Не останется ничего... кроме очков. Вы сами не знаете, зачем их сохранили. Вы человек не импульсивный и обычно не берете сувениров. Но здесь ведь дело в другом, верно? Через эти линзы человек видел мир преступности и политики, верности и предательства, и он научился выворачивать все это в свою пользу.\nВладелец этих очков сплел заговор, превосходящий ваше самое смелое воображение. Возможно, если вы будете держать их при себе, вы сможете увидеть то же, что видел он.",
	["bm_msk_waytexase"] = "По-техасски",
	["bm_msk_waytexase_desc"] = "Будь стойким. Будь гордым. Будь упрямым. Будь дружелюбным. И чертовски хорошо стреляй из револьвера.\nОсобенно последнее.",
	["bm_msk_zoothat_black"] = "Преступный ум (Фокус)",
	["bm_msk_zoothat_black_desc"] = "Все твои мысли о деньгах, а деньги - на уме.",
	["bm_msk_zoothat_blue"] = "Преступный ум (Хитрость)",
	["bm_msk_zoothat_blue_desc"] = "Копы ненавидят, когда преступники носят синее. Это чертовски путает их во время перестрелки.",
	["bm_msk_zoothat_red"] = "Преступный ум (Ярость)",
	["bm_msk_zoothat_red_desc"] = "Некоторые говорят, что у тебя проблемы с гневом. Этих людей больше нет рядом.",
	["bm_msk_zoothat_yellow"] = "Преступный ум (Обман)",
	["bm_msk_zoothat_yellow_desc"] = "Твой жизнерадостный вид скрывает темную и безжалостную хитрость.",

--Одежда
    ["bm_mtl_strip_paint"] = "Смывка краски",
	["bm_suit_bikerjacket_desc"] = "Они появляются из густого тумана выхлопных газов, мерцая в мареве - кошмарный мираж. Они скачут на ревущих стальных скакунах, и скачут быстро. Их слишком много, чтобы сосчитать. Слишком сильны, чтобы идти напролом. Освободите дорогу, или они закатают вас в асфальт.",
	["bm_suit_bikerjacket_green"] = "Черная магия",
	["bm_suit_bikerjacket_green_desc"] = "Говорят, это чудо, что вы выжили в той аварии, но, по правде говоря, это было ближе к некромантии.",
	["bm_suit_bikerjacket_red"] = "Скоростная полоса",
	["bm_suit_bikerjacket_red_desc"] = "Конечно, вы не заметили знаков! Вы ехали слишком быстро.",
	["bm_suit_bikervest"] = "Дорожная ярость",
	["bm_suit_bikervest_camo"] = "Королевская боль",
	["bm_suit_bikervest_camo_desc"] = "Тяжела голова, что пытается пойти против короны.",
	["bm_suit_bikervest_desc"] = "Большинство считает это мимолетным состоянием, жестоким порывом, который проходит, как проносящаяся фура. Но вы знаете правду о дорожной ярости: это стиль жизни. Для вас мир - это одна большая десятиполосная магистраль, застрявшая в глухой пробке. Вы собираетесь плестись со всем стадом? Или стиснете зубы, вдавите педаль в пол и пробьетесь вперед? Помните: если кто-то пострадал, ему следовало лучше учиться водить.",
	["bm_suit_bikervest_red"] = "Поджигатель",
	["bm_suit_bikervest_red_desc"] = "Огонь следует за тобой.",
	["bm_suit_bikervest_white"] = "Винтик поехал",
	["bm_suit_bikervest_white_desc"] = "Ты можешь починить свой мотоцикл, но не можешь починить себя. Ну и что? Ты механик, а не гребаный мозгоправ.",
	["bm_suit_boss_suit_desc"] = "Созданный по мотивам традиционного суньятсеновского френча (костюма Мао), этот изысканный наряд источает ауру истинного лидера.",
	["bm_suit_bossflag"] = "Техасские сокровища",
	["bm_suit_bossflag_desc"] = "Хей! Помните то время, когда мы штурмовали базу контрабандистов оружия на ранчо в глуши Техаса? А потом ограбили поезд в Форт-Уэрте, буквально подняв состав прямо с путей? А потом нас втянули в разборки двух продажных нефтяных баронов, из-за чего нам пришлось разнести штаб-квартиру корпорации в Далласе, а после взорвать к чертям морскую буровую платформу? Ха-ха-ха, чувак. Славные были времена. Сла-а-авные.",
	["bm_suit_bthekid"] = "Беглец из тюрьмы",
	["bm_suit_bthekid_desc"] = "После долгой и неутомимой охоты закон наконец добрался до Билли Кида. Его заперли в камере, заковали в кандалы и приговорили к повешению. Казалось, его время истекло, но когда человек знает, что стоит на пороге смерти, он пойдет на все, чтобы выбраться. Обычный заключенный никогда бы не смог украсть пистолет у охранника и пробиться с боем из тюрьмы. К несчастью для шерифов Линкольна, Нью-Мексико, они забыли... Билли Кид не был обычным заключенным.",
	["bm_suit_cargocasual"] = "Урбанист",
	["bm_suit_cargocasual_cassette"] = "Включай запись",
	["bm_suit_cargocasual_cassette_desc"] = "Что за ограбление без хорошего саундтрека?",
	["bm_suit_cargocasual_desc"] = "Воплощение стиля и непринужденности, этот наряд идеально подходит для разведки обстановки на объектах в городских условиях. Когда люди увидят вас, они подумают: \"Посмотрите на этого парня! Похоже, его очень интересует кодовая панель на банковском хранилище. И гардероб у него убойный! Интересно, где он взял такую рубашку. Эх, мне бы такие шмотки...\"\nЗаметили, как часть про \"банковское хранилище\" изящно затерялась?",
	["bm_suit_cargocasual_monke"] = "Был здесь первым",
	["bm_suit_cargocasual_monke_desc"] = "Он воровал бананы еще до того, как первые люди обобрали Землю.",
	["bm_suit_cargocasual_texas"] = "Положение дел",
	["bm_suit_cargocasual_texas_desc"] = "Так откуда ты родом... Оу.",
	["bm_suit_cassidy"] = "Дикая банда",
	["bm_suit_cassidy_desc"] = "Грабитель хорош настолько, насколько хороша его банда, и Бутч Кэссиди это знал. Его \"Дикая банда\" была грозой Старого Веста, и они оставались сплоченной командой до самого конца. О лучших коллегах нельзя и мечтать.",
	["bm_suit_corl"] = "Криминальный авторитет",
	["bm_suit_corl_desc"] = "Власть бывает разной. Это сила подавлять врагов. Это влияние, позволяющее управлять другими одним лишь словом. Это хитрость, помогающая думать на пять шагов вперед. Освоение одной формы может привести вас на самую вершину. Освоение всех - гарантирует, что вы там останетесь.",
	["bm_suit_darkprince"] = "Князь тьмы",
	["bm_suit_darkprince_desc"] = "Для Дьявола обуви не шьют. Века поисков, но нет бренда, который подошел бы к его копытам и выдержал адский жар его долгих прогулок по Преисподней. Вот почему он носит этот пижонский жилет и пиджак - он надеется, что они отвлекут вас от его босоногого позора!",
	["bm_suit_dgame"] = "Мертвый худи",
	["bm_suit_dgame_default"] = "Черный худи",
	["bm_suit_dgame_default_desc"] = "Эту толстовку уже никто и не носит.",
	["bm_suit_dgame_desc"] = "Если эта игра действительно мертва, то этот текст никто не прочитает. Так что я могу писать здесь вообще все, что захочу. Хммм... Тонкая картошка фри - лучшая форма картошки. Извините, но дольки и толстый картофель слишком плотные. Если бы я хотел обычную вареную картошку, я бы ее и заказал. Я хочу фри. Тонкую. Хрустящую. Аж есть захотелось, пока думал об этом. Ладно. Не знаю, как это закончить. Конец?",
	["bm_suit_dgame_white"] = "Белый худи",
	["bm_suit_dgame_white_desc"] = "Респект прекрасным грабителям, которые поддерживают жизнь в этой мертвой игре!",
	["bm_suit_dodsuit"] = "Мертвый стрелок",
	["bm_suit_dodsuit_desc"] = " Такому пижону-ганслингеру не место под землей! Ты же испачкаешь свое сомбреро! Лови маленький секрет о дуэлях: то, что в тебя попали, еще не значит, что ты проиграл. Ты проиграл, только если не поднялся обратно.",
	["bm_suit_elfsuit_default_desc"] = "Рождественские елки никогда не сдаются.",
	["bm_suit_elfsuit_desc"] = "Вы, вероятно, не слышали о Непослушных эльфах. Тимми уж точно не слышал. Он весь год вел себя прилежно, чтобы получить модельку поезда, которую так сильно хотел, но стоило ему открыть подарок, как он тут же вернулся к плевкам на ковер и разогреванию хомячков в микроволновке. Он думал, что обманул систему, но Санту никто не обставит. Если ты выкинешь такое дерьмо, Санта пришлет Непослушных эльфов, чтобы вернуть игрушки, и, возможно, переломать тебе пальцы для профилактики. Так что помните: если вы попали в Список послушных, оставайтесь там, иначе Непослушные эльфы устроят вам веселую жизнь. Спросите у Тимми.",
	["bm_suit_elfsuit"] = "Маленький грабитель Санты",
	["bm_suit_elfsuit_red"] = "Дух Рождества",
	["bm_suit_elfsuit_red_desc"] = "Делаем атмосферу праздничной и яркой.",
	["bm_suit_elfsuit_violet"] = "Список непослушных",
	["bm_suit_elfsuit_violet_desc"] = "Не расстраивайся. Все самые крутые люди в итоге оказываются именно здесь.",
	["bm_suit_elfsuit_yellow"] = "Зимнее солнце",
	["bm_suit_elfsuit_yellow_desc"] = "Смени это горячее какао на пинья коладу!",
	["bm_suit_enforcer_suit_desc"] = "Костюм современного кроя с традиционными элементами, который носят \"Красные шесты\" из синдиката \"Золотой кинжал\".",
	["bm_suit_gangzsta"] = "Гангстерский рай",
	["bm_suit_gangzsta_blue"] = "Отпущенные грехи",
	["bm_suit_gangzsta_blue_desc"] = "Прощай, но никогда не забывай.",
	["bm_suit_gangzsta_default"] = "Еретик",
	["bm_suit_gangzsta_default_desc"] = "Вы говорите правду, когда все остальные молчат.",
	["bm_suit_gangzsta_desc"] = "Каков пастырь, такова и паства. Ваш приход состоит из воров и дегенератов, и вы не желаете им другой судьбы. В чистоте нет прибыли. Деньги - ваш бог, улицы - ваш храм, а проповедь вы читаете градом пуль. Да познают ваши последователи праведный путь к вечному богатству. И да отправятся ваши враги прямиком через долину смертной тени.",
	["bm_suit_gangzsta_red"] = "Нечестивый",
	["bm_suit_gangzsta_red_desc"] = "Грех - это вопрос точки зрения.",
	["bm_suit_gangzsta_yellow"] = "Божественный",
	["bm_suit_gangzsta_yellow_desc"] = "Поднимись над всеми, а затем иди еще дальше.",
	["bm_suit_ghostly"] = "Одержимый призраками",
	["bm_suit_ghostly_desc"] = "Должен сказать, мне очень нравится твой костюм призрака. Развевающиеся лохмотья, облако тумана - отличная работа. Умного парня вроде меня этим не провести, но копы точно наложат в штаны! Правда, должен спросить... Как ты так висишь в воздухе? И как тебя зовут, напомни? Я не помню, чтобы мы нанимали пятого парня на это дело.\nОу, приятель! У тебя глаза светятся! Как ты это... Э-э... Оу... Оу, черт...",
	["bm_suit_jessjames"] = "Бушвакер",
	["bm_suit_jessjames_desc"] = "Бунтари. Убийцы. Патриоты. Воры. У каждого было свое описание для бушвакеров - партизанских отрядов, оставивших глубокий след в американской истории. От Войны за независимость до Гражданской войны они зубами и когтями дрались за то, что принадлежало им. Любили вы их или ненавидели, нельзя отрицать их роль в становлении титана Дикого Запада: именно они научили Джесси Джеймса стрелять.",
	["bm_suit_leatherfluff"] = "Суровые улицы",
	["bm_suit_leatherfluff_bats"] = "Летучие мыши",
	["bm_suit_leatherfluff_bats_desc"] = "Немного жутковатой атмосферы.",
	["bm_suit_leatherfluff_desc"] = "Такая куртка не нуждается в лишних украшениях. В ней сочетаются вся суровость прерий и весь стиль большого города. Но вы любите заходить дальше. Ничего лишнего, просто небольшая эмблема, дающая миру понять, кто вы такой. В конце концов, символ стоит тысячи слов.",
	["bm_suit_leatherfluff_dots"] = "Полный комплект",
	["bm_suit_leatherfluff_dots_desc"] = "Удачной охоты!",
	["bm_suit_leatherfluff_lightning"] = "Удар молнии",
	["bm_suit_leatherfluff_lightning_desc"] = "Станьте встряской для системы.",
	["bm_suit_mocow"] = "Вестерн-шик",
	["bm_suit_mocow_desc"] = "Весь культовый понт американского ковбоя, но без грязи и вони скота. С таким прикидом вы станете желанным гостем как в ночном клубе, так и в салуне Старого Веста.",
	["bm_suit_moneysuit"] = "Денежный поток",
	["bm_suit_moneysuit_default"] = "Отмывание денег",
	["bm_suit_moneysuit_default_desc"] = "Бери деньги и БЕГИ!",
	["bm_suit_moneysuit_desc"] = "Короче, это мое первое ограбление, ладно? Какой-то крошечный филиал банка в глухомани. Я думаю, в хранилище денег не будет, только в кассах. Двух сумок за глаза хватит. Оказалось, касс там гораздо больше, чем я думал. Да и банк этот ни фига не крошечный, потому что хранилище забито под завязку! Но вы меня знаете, я ни доллара не оставлю. Так что после того, как я набил свои сумки, банковские сумки и все кошельки с рюкзаками, что отобрал у гражданских, я снял свою рубашку, трусы и... ну... проявил смекалку.\nПоймал пару порезов бумагой там, где солнце не светит, но оно того стоило!\n",
	["bm_suit_moneysuit_gold"] = "Золотой стандарт",
	["bm_suit_moneysuit_gold_desc"] = "Говорят, жадность - это огонь, сжигающий душу человека, но вам он к лицу.",
	["bm_suit_moneysuit_money"] = "Одет для успеха",
	["bm_suit_moneysuit_money_desc"] = "Вы выглядите на миллион долларов, плюс-минус. Надеюсь, дождя не будет.",
	["bm_suit_newhorizon"] = "Новый горизонт",
	["bm_suit_newhorizon_desc"] = "Наступает новая эра. Альянсы сформированы. Курс проложен. Это огненное зарево впереди становится только ярче.\n\nВы готовы к тому, что будет дальше?",
	["bm_suit_nightwalker"] = "Граф",
	["bm_suit_nightwalker_desc"] = "Будучи бессмертным порождением ночи, вы повидали немало модных трендов. Некоторые образы стареют хуже других, но вы знаете, что ничто так не идет нежити, как утонченная элегантность аристократа XVIII века. Вы кровопийца с хорошим вкусом!",
	["bm_suit_pda10_acc_tacticalbdu_camo"] = "Тактический камуфляж",
	["bm_suit_pda10_acc_tacticalbdu_camo_desc"] = "Ночь имеет много оттенков. С этой формой BDU вы сольетесь с каждым из них.",
	["bm_suit_pda10_thug_gold"] = "Золотой бомбер Дракона",
	["bm_suit_pda10_thug_gold_desc"] = "Не прячьте свое процветание. Пусть мир видит ваш сияющий триумф. Настоящие друзья будут хвалить вас, а остальных поглотит зависть.",
	["bm_suit_puffervest"] = "При параде",
	["bm_suit_puffervest_blue"] = "Ночная жизнь",
	["bm_suit_puffervest_blue_desc"] = "Когда солнце заходит, время надевать жилет.",
	["bm_suit_puffervest_desc"] = "Живете в крутом городе, но погода портится? Наденьте жилет! Собираетесь на тусовку у костра? Жилет! Вы путешественник во времени, играющий на гитаре? Оранжевый жилет! Жилеты - это тема. Они греют, отлично выглядят, а некоторые еще и работают как спасательные жилеты.",
	["bm_suit_puffervest_grey"] = "Суровый",
	["bm_suit_puffervest_grey_desc"] = "По одному только вашему виду они ни за что не догадаются.",
	["bm_suit_puffervest_red"] = "Нортсайд",
	["bm_suit_puffervest_red_desc"] = "Отлично выглядеть и быть в тепле - вещи вполне совместимые.",
	["bm_suit_railroad"] = "Начальник поезда",
	["bm_suit_railroad_desc"] = "Кто сильнее локомотива? Тот, кто им управляет, вот кто. Вы решаете, когда поезд отправляется, как быстро он идет и ради кого останавливается (если вообще останавливается). Вы могли бы пустить всю эту операцию под откос, если бы захотели, но не хотите. Вот почему вас поставили главным.",
	["bm_suit_roclown"] = "Человек в бочке",
	["bm_suit_roclown_desc"] = "Это факт: \"люди в бочках\" - высший класс родео-клоунов. У них единственная работа, которая имеет значение: развлекать публику. Не давать людям понять, что дикий бык может выпустить кому-нибудь кишки прямо у них на глазах. Это отвлечение внимания... оно является ключевым во всем шоу.\nКогда вы идете на ограбление, вы - этот человек в бочке. Мастер контроля толпы. \"Посмотрите на меня, народ! Не обращайте внимания на стрельбу за стойкой кассира! Не думайте бежать, ведь наши пули бегают быстрее! Все глаза на меня, леди и джентльмены! Руки на голову, и смотрим на клоуна!\"",
	["bm_suit_sambass"] = "Грабитель поездов",
	["bm_suit_sambass_desc"] = "Когда Сэм Басс грабил тот поезд Union Pacific, он не знал, что совершает крупнейшее ограбление поезда в истории железной дороги. Он не понимал, что сорвет куш в золотых монетах, которого хватит на всю жизнь, что позволит ему идти на преступления ради острых ощущений, а не ради наживы. Достаточно одного поступка, чтобы стать легендой, и в 1877 году Басс наткнулся на золотую жилу.",
	["bm_suit_sleekygent"] = "Успешный бизнес",
	["bm_suit_sleekygent_desc"] = "Во многом вы просто очередной вор. Чистите карманы. Тащите добро из хранилищ. Воспринимаете жизнь как большую игру цифр. Но у вас есть одна черта: вы умны. Вы придумали, как заставить эти карманы пустеть самостоятельно. Научились высушивать хранилища, не нарушая ни единого закона. А та игра цифр? Вы выигрываете в ней с разгромным счетом. Корпоративный мир - это игровая площадка для преступника; вот секрет вашего кровью и потом заработанного успеха. Так что нет, вы не просто вор. Вы исключительный вор.",
	["bm_suit_var_bikerjacket_suit_default"] = "Трасса 66",
	["bm_suit_var_bikerjacket_suit_default_desc"] = "Главная улица Америки проходит через восемь разных штатов. Угадайте, какой из них самый большой.",
	["bm_suit_var_bikervest_default"] = "Безрассудный",
	["bm_suit_var_bikervest_default_desc"] = "Живи быстро, гоняй быстрее. Смерть - всего лишь пит-стоп.",
	["bm_suit_var_boss_suit_default_desc"] = "В моменты возмездия этот костюм подходит как нельзя кстати.",
	["bm_suit_var_boss_suit_green_desc"] = "Хитрый, выжидающий под поверхностью - владелец этого одеяния знает цену сокрытию своей истинной силы до тех пор, пока не придет время наносить удар.",
	["bm_suit_var_boss_suit_red_desc"] = "Стильный и несущий на себе отпечаток удачи, он отлично подходит для любых случаев.",
	["bm_suit_var_boss_suit_yellow_desc"] = "Золото, в конце концов, лучший металл, так почему бы не носить его вплетенным в роскошный, замысловатый узор?",
	["bm_suit_var_cargocasual_suit_default"] = "Серая зона",
	["bm_suit_var_cargocasual_suit_default_desc"] = "Вы живете вне рамок понятий добра и зла.",
	["bm_suit_var_enforcer_suit_blood_desc"] = "Одна из самых популярных версий; сочетание черного и белого никогда не подведет... Главное - не испачкай белое кровью.",
	["bm_suit_var_enforcer_suit_default_desc"] = "Эта версия более сдержанная и идеально подходит, когда вам нужно слиться с окружением.",
	["bm_suit_var_enforcer_suit_dragon_desc"] = "Если вы хотите принарядиться для битвы не на жизнь, а на смерть, вы всегда можете соблюсти формальности.",
	["bm_suit_var_enforcer_suit_red_dragon_desc"] = "Будь то дуэль насмерть, жестокая перестрелка или важные переговоры, этот вариант вас не подведет.",
	["bm_suit_var_leatherfluff_suit_default"] = "Заявление",
	["bm_suit_var_leatherfluff_suit_default_desc"] = "Никогда не забывай, откуда ты пришел.",
	["bm_suit_var_puffervest_suit_default"] = "Побережье",
	["bm_suit_var_puffervest_suit_default_desc"] = "Почувствуйте этот океанский бриз!",
})